object AppLogger {
    private const val MAX_LOG_CHUNK = 4000

    fun init() {
        if (Timber.forest().isEmpty()) {
            Timber.plant(ProductionVerboseTree())
        }
    }

    fun v(tag: String, message: String) = chunkedLog(Log.VERBOSE, tag, message)
    fun d(tag: String, message: String) = chunkedLog(Log.DEBUG, tag, message)
    fun i(tag: String, message: String) = chunkedLog(Log.INFO, tag, message)
    fun w(tag: String, message: String, throwable: Throwable? = null) = chunkedLog(Log.WARN, tag, appendThrowable(message, throwable))
    fun e(tag: String, message: String, throwable: Throwable? = null) = chunkedLog(Log.ERROR, tag, appendThrowable(message, throwable))

    fun logException(tag: String, throwable: Throwable, context: String? = null) {
        val message = buildString {
            if (!context.isNullOrBlank()) {
                append(context)
                append('\n')
            }
            append(Log.getStackTraceString(throwable))
        }
        chunkedLog(Log.ERROR, tag, message)
    }

    fun logAuthAttempt(
        username: String?,
        userId: String? = null,
        success: Boolean,
        method: String,
        failureReason: String? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        val payload = buildString {
            append("AUTH_ATTEMPT")
            append("\nmethod=").append(method)
            append("\nusername=").append(username ?: "null")
            append("\nuserId=").append(userId ?: "null")
            append("\nsuccess=").append(success)
            if (!failureReason.isNullOrBlank()) append("\nfailureReason=").append(failureReason)
            if (metadata.isNotEmpty()) {
                append("\nmetadata=")
                append(metadata.entries.joinToString(", ") { "${it.key}=${it.value}" })
            }
        }
        chunkedLog(Log.VERBOSE, "AuthLogger", payload)
    }

    fun logDbQuery(
        sql: String,
        params: List<Any?> = emptyList(),
        args: Map<String, Any?> = emptyMap(),
        durationMs: Long? = null,
        rowsAffected: Int? = null
    ) {
        val payload = buildString {
            append("DB_QUERY")
            append("\nsql=").append(sql)
            append("\nparams=").append(params.joinToString(prefix = "[", postfix = "]") { it.safeToLog() })
            if (args.isNotEmpty()) {
                append("\nargs=")
                append(args.entries.joinToString(", ") { "${it.key}=${it.value.safeToLog()}" })
            }
            if (durationMs != null) append("\ndurationMs=").append(durationMs)
            if (rowsAffected != null) append("\nrowsAffected=").append(rowsAffected)
        }
        chunkedLog(Log.VERBOSE, "DatabaseLogger", payload)
    }

    private fun appendThrowable(message: String, throwable: Throwable?): String {
        return if (throwable == null) message else "$message\n${Log.getStackTraceString(throwable)}"
    }

    private fun chunkedLog(priority: Int, tag: String, message: String) {
        if (message.length <= MAX_LOG_CHUNK) {
            Timber.tag(tag).log(priority, message)
            return
        }
        var start = 0
        while (start < message.length) {
            val end = (start + MAX_LOG_CHUNK).coerceAtMost(message.length)
            Timber.tag(tag).log(priority, message.substring(start, end))
            start = end
        }
    }

    private fun Any?.safeToLog(): String = when (this) {
        null -> "null"
        is ByteArray -> joinToString(prefix = "[", postfix = "]")
        else -> toString()
    }
}

class ProductionVerboseTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val resolvedTag = tag ?: "AppLogger"
        when (priority) {
            Log.VERBOSE -> Log.v(resolvedTag, message, t)
            Log.DEBUG -> Log.d(resolvedTag, message, t)
            Log.INFO -> Log.i(resolvedTag, message, t)
            Log.WARN -> Log.w(resolvedTag, message, t)
            Log.ERROR -> Log.e(resolvedTag, message, t)
            Log.ASSERT -> Log.wtf(resolvedTag, message, t)
            else -> Log.println(priority, resolvedTag, message)
        }
    }
}

class VerboseHttpLoggingInterceptor(
    private val logger: (String) -> Unit = { AppLogger.v("ApiLogger", it) },
    private val logResponseBody: Boolean = true,
    private val logRequestBody: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        logRequest(request)

        val startNs = System.nanoTime()
        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            logResponse(response, tookMs)
            response
        } catch (e: Exception) {
            logger(
                buildString {
                    append("HTTP_CALL_FAILED")
                    append("\nmethod=").append(request.method)
                    append("\nurl=").append(request.url)
                    append("\nheaders=").append(request.headers.toMultimap())
                    append("\nexception=").append(Log.getStackTraceString(e))
                }
            )
            throw e
        }
    }

    private fun logRequest(request: Request) {
        logger(
            buildString {
                append("HTTP_REQUEST")
                append("\nmethod=").append(request.method)
                append("\nurl=").append(request.url)
                append("\nheaders=\n").append(headersToString(request.headers))
                if (logRequestBody) {
                    append("\nbody=\n").append(requestBodyToString(request))
                }
            }
        )
    }

    private fun logResponse(response: Response, tookMs: Long) {
        val rawBodyString = if (logResponseBody) peekBodyAsString(response) else "<skipped>"
        logger(
            buildString {
                append("HTTP_RESPONSE")
                append("\nurl=").append(response.request.url)
                append("\ncode=").append(response.code)
                append("\nmessage=").append(response.message)
                append("\nprotocol=").append(response.protocol)
                append("\ndurationMs=").append(tookMs)
                append("\nheaders=\n").append(headersToString(response.headers))
                append("\nbody=\n").append(rawBodyString)
            }
        )
    }

    private fun headersToString(headers: Headers): String {
        if (headers.size == 0) return "<empty>"
        val sb = StringBuilder()
        for (i in 0 until headers.size) {
            sb.append(headers.name(i)).append(": ").append(headers.value(i)).append('\n')
        }
        return sb.toString().trimEnd()
    }

    private fun requestBodyToString(request: Request): String {
        return try {
            val body = request.body ?: return "<empty>"
            val buffer = Buffer()
            body.writeTo(buffer)
            val charset = body.contentType().charsetOrUtf8()
            buffer.readString(charset)
        } catch (e: Exception) {
            "Unable to read request body\n${Log.getStackTraceString(e)}"
        }
    }

    private fun peekBodyAsString(response: Response): String {
        return try {
            val contentLength = response.body?.contentLength() ?: 0L
            val peeked = response.peekBody(if (contentLength > 0) contentLength else 1024 * 1024)
            val charset = peeked.contentType().charsetOrUtf8()
            peeked.source().request(Long.MAX_VALUE)
            peeked.source().buffer.clone().readString(charset)
        } catch (e: Exception) {
            "Unable to read response body\n${Log.getStackTraceString(e)}"
        }
    }

    private fun MediaType?.charsetOrUtf8(): Charset = this?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
}

object LoggingHttpClientFactory {
    fun create(): OkHttpClient {
        return OkHttpClient.Builder()
            .addInterceptor(VerboseHttpLoggingInterceptor())
            .build()
    }
}

object ExceptionLogging {
    fun installGlobalHandler() {
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            AppLogger.logException(
                tag = "CrashLogger",
                throwable = throwable,
                context = "Uncaught exception on thread=${thread.name}"
            )
            defaultHandler?.uncaughtException(thread, throwable)
        }
    }

    inline fun <T> runCatchingLogged(
        tag: String,
        context: String? = null,
        block: () -> T
    ): Result<T> {
        return kotlin.runCatching(block).onFailure {
            AppLogger.logException(tag, it, context)
        }
    }
}

interface AuthenticationLogger {
