}

class AuthenticationLoggerImpl : AuthenticationLogger {
    override fun logLoginSuccess(username: String?, userId: String?, method: String, metadata: Map<String, Any?>) {
        AppLogger.logAuthAttempt(
            username = username,
            userId = userId,
            success = true,
            method = method,
            metadata = metadata
