    override fun logLoginFailure(username: String?, method: String, reason: String, metadata: Map<String, Any?>) {
        AppLogger.logAuthAttempt(
            username = username,
            success = false,
            method = method,
            failureReason = reason,
            metadata = metadata
        )
    }
}

